-- 1. Orphan schedule blocks (parent plan was deleted)
DELETE sb FROM scheduleBlocks sb LEFT JOIN dailyPlans dp ON dp.id = sb.planId WHERE dp.id IS NULL;

-- 2. Schedule blocks whose plan is in the deletion set (avoid leaving new orphans)
DELETE sb FROM scheduleBlocks sb JOIN dailyPlans dp ON dp.id = sb.planId WHERE dp.date > '2026-12-31';

-- 3. Future test-seed daily plans
DELETE FROM dailyPlans WHERE date > '2026-12-31';

-- 4. Tutor roster cleanup
UPDATE tutors SET active = 0, notes = CONCAT(IFNULL(notes,''),' | 2026-05-20: Mom audit — deactivated; school year ends Tue May 19 was Sophie last day.') WHERE id IN (510001, 60009);
DELETE FROM tutors WHERE id IN (1, 510003, 750010);

-- 5. Drop the stuck queued nightly emails (4 sent rows retained for audit)
DELETE FROM nightlyAgendaEmails WHERE status = 'queued';

-- 6. Verify post-cleanup
SELECT 'tutors_active' AS metric, COUNT(*) AS value FROM tutors WHERE active = 1
UNION ALL SELECT 'tutors_total', COUNT(*) FROM tutors
UNION ALL SELECT 'plans_total', COUNT(*) FROM dailyPlans
UNION ALL SELECT 'blocks_total', COUNT(*) FROM scheduleBlocks
UNION ALL SELECT 'blocks_orphan', COUNT(*) FROM scheduleBlocks sb LEFT JOIN dailyPlans dp ON dp.id = sb.planId WHERE dp.id IS NULL
UNION ALL SELECT 'nightly_email_queued', COUNT(*) FROM nightlyAgendaEmails WHERE status='queued'
UNION ALL SELECT 'nightly_email_sent', COUNT(*) FROM nightlyAgendaEmails WHERE status='sent';

